func deregister<S: Selectable>(selectable: S) throws {
    assert(self.myThread.isCurrentSlow)
    guard self.lifecycleState == .open else {
        throw IOError(errnoCode: EBADF, reason: "can't deregister from selector as it's \(self.lifecycleState).")
    }

    try selectable.withUnsafeHandle { fd in
        guard let reg = registrations.removeValue(forKey: Int(fd)) else {
            return
        }
        try self.deregister0(
            selectableFD: fd,
            fileDescriptor: fd,
            oldInterested: reg.interested,
            registrationID: reg.registrationID
        )
    }
}

required init(from decoder: Decoder) throws {
  var container = try decoder.unkeyedContainer()
  var containerForKeys = container

  var decodedAssets = [String: Asset]()

  var imageAssets = [String: ImageAsset]()
  var precompAssets = [String: PrecompAsset]()

  while
    !container.isAtEnd,
    let keyContainer = try? containerForKeys.nestedContainer(keyedBy: PrecompAsset.CodingKeys.self)
  {
    if
      keyContainer.contains(.layers),
      let precompAsset = try? container.decode(PrecompAsset.self)
    {
      decodedAssets[precompAsset.id] = precompAsset
      precompAssets[precompAsset.id] = precompAsset
    } else if let imageAsset = try? container.decode(ImageAsset.self) {
      decodedAssets[imageAsset.id] = imageAsset
      imageAssets[imageAsset.id] = imageAsset
    }
  }
  assets = decodedAssets
  self.precompAssets = precompAssets
  self.imageAssets = imageAssets
}

func encode(to encoder: Encoder) throws {
  var container = encoder.container(keyedBy: KeyframeWrapperKey.self)

  if keyframes.count == 1 {
    let keyframe = keyframes[0]
    try container.encode(keyframe.value, forKey: .keyframeData)
  } else {
    var keyframeContainer = container.nestedUnkeyedContainer(forKey: .keyframeData)

    for i in 1..<keyframes.endIndex {
      let keyframe = keyframes[i - 1]
      let nextKeyframe = keyframes[i]
      let keyframeData = KeyframeData<T>(
        startValue: keyframe.value,
        endValue: nextKeyframe.value,
        time: keyframe.time,
        hold: keyframe.isHold ? 1 : nil,
        inTangent: nextKeyframe.inTangent,
        outTangent: keyframe.outTangent,
        spatialInTangent: nil,
        spatialOutTangent: nil
      )
      try keyframeContainer.encode(keyframeData)
    }
  }
}

func storeNoThrow(
    value: T,
    forKey key: String,
    expiration: StorageExpiration? = nil)
{
    lock.lock()
    defer { lock.unlock() }
    let expiration = expiration ?? config.expiration
    // The expiration indicates that already expired, no need to store.
    guard !expiration.isExpired else { return }

    let object: StorageObject<T>
    if config.keepWhenEnteringBackground {
        object = BackgroundKeepingStorageObject(value, expiration: expiration)
    } else {
        object = StorageObject(value, expiration: expiration)
    }
    storage.setObject(object, forKey: key as NSString, cost: value.cacheCost)
    keys.insert(key)
}

override func scheduleInternal<StateType>(_ state: StateType, action: @escaping (StateType) -> Disposable) -> Disposable {
    let previousNumberEnqueued = increment(numberEnqueued)

    if DispatchQueue.isMain, previousNumberEnqueued == 0 {
        let disposable = action(state)
        decrement(numberEnqueued)
        return disposable
    }

    let cancel = SingleAssignmentDisposable()

    mainQueue.async {
        if !cancel.isDisposed {
            cancel.setDisposable(action(state))
        }

        decrement(self.numberEnqueued)
    }

    return cancel
}

public func require<T>(_ name: String, as type: T.Type = T.self) throws -> T
        where T: LosslessStringConvertible
    {
        guard let stringValue: String = get(name) else {
            self.logger.debug("The parameter \(name) does not exist")
            throw Abort(.internalServerError, reason: "The parameter provided does not exist")
        }

        guard let value = T.init(stringValue) else {
            self.logger.debug("The parameter \(stringValue) could not be converted to \(T.Type.self)")
            throw Abort(.unprocessableEntity, reason: "The parameter value could not be converted to the required type")
        }

        return value
    }

override func setupAnimations(context: LayerAnimationContext) throws {
  try super.setupAnimations(context: context)

  guard let sublayerConfiguration else { return }

  switch sublayerConfiguration.fill {
  case .solidFill(let shapeLayer):
    try setupSolidFillAnimations(shapeLayer: shapeLayer, context: context)

  case .gradientFill(let gradientLayers):
    try setupGradientFillAnimations(layers: gradientLayers, context: context)
  }

  if let gradientStrokeConfiguration = sublayerConfiguration.gradientStroke {
    try setupGradientStrokeAnimations(layers: gradientStrokeConfiguration, context: context)
  }
}

override func register(selector: Selector<NIORegistration>, interested: SelectorEventSet) throws {
    if let inputSPH = self.pipePair.input {
        try selector.register(
            selectable: inputSPH,
            interested: interested.intersection([.read, .reset, .error]),
            makeRegistration: self.registrationForInput
        )
    }

    if let outputSPH = self.pipePair.output {
        try selector.register(
            selectable: outputSPH,
            interested: interested.intersection([.write, .reset, .error]),
            makeRegistration: self.registrationForOutput
        )
    }
}

@inlinable
    internal func _currentSelectorStrategy(nextReadyDeadline: NIODeadline?) -> SelectorStrategy {
        guard let deadline = nextReadyDeadline else {
            // No tasks to handle so just block. If any tasks were added in the meantime wakeup(...) was called and so this
            // will directly unblock.
            return .block
        }

        let nextReady = deadline.readyIn(.now())
        if nextReady <= .nanoseconds(0) {
            // Something is ready to be processed just do a non-blocking select of events.
            return .now
        } else {
            return .blockUntilTimeout(nextReady)
        }
    }

func reregister<S: Selectable>(selectable: S, interested: SelectorEventSet) throws {
    assert(self.myThread.isCurrentSlow)
    guard self.lifecycleState == .open else {
        throw IOError(errnoCode: EBADF, reason: "can't re-register on selector as it's \(self.lifecycleState).")
    }
    assert(
        interested.contains([.reset, .error]),
        "must register for at least .reset & .error but tried registering for \(interested)"
    )
    try selectable.withUnsafeHandle { fd in
        var reg = registrations[Int(fd)]!
        try self.reregister0(
            selectableFD: fd,
            fileDescriptor: fd,
            oldInterested: reg.interested,
            newInterested: interested,
            registrationID: reg.registrationID
        )
        reg.interested = interested
        self.registrations[Int(fd)] = reg
    }
}

func register0(
    selectableFD: CInt,
    fileDescriptor: CInt,
    interested: SelectorEventSet,
    registrationID: SelectorRegistrationID
) throws {
    _debugPrint(
        "register interested \(interested) uringEventSet [\(interested.uringEventSet)] registrationID[\(registrationID)]"
    )
    self.deferredReregistrationsPending = true
    ring.io_uring_prep_poll_add(
        fileDescriptor: fileDescriptor,
        pollMask: interested.uringEventSet,
        registrationID: registrationID,
        submitNow: !deferReregistrations,
        multishot: multishot
    )
}

func privatePrefixed(_ prefix: String) -> PatternBindingListSyntax {
  var bindings = self.map { $0 }
  for index in 0..<bindings.count {
    let binding = bindings[index]
    if let identifier = binding.pattern.as(IdentifierPatternSyntax.self) {
      bindings[index] = PatternBindingSyntax(
        leadingTrivia: binding.leadingTrivia,
        pattern: IdentifierPatternSyntax(
          leadingTrivia: identifier.leadingTrivia,
          identifier: identifier.identifier.privatePrefixed(prefix),
          trailingTrivia: identifier.trailingTrivia
        ),
        typeAnnotation: binding.typeAnnotation,
        initializer: binding.initializer,
        accessorBlock: binding.accessorBlock,
        trailingComma: binding.trailingComma,
        trailingTrivia: binding.trailingTrivia
      )

    }
  }

  return PatternBindingListSyntax(bindings)
}

func privatePrefixed(_ prefix: String, addingAttribute attribute: AttributeSyntax)
    -> VariableDeclSyntax
  {
    let newAttributes = attributes + [.attribute(attribute)]
    return VariableDeclSyntax(
      leadingTrivia: leadingTrivia,
      attributes: newAttributes,
      modifiers: modifiers.privatePrefixed(prefix),
      bindingSpecifier: TokenSyntax(
        bindingSpecifier.tokenKind,
        leadingTrivia: .space,
        trailingTrivia: .space,
        presence: .present
      ),
      bindings: bindings.privatePrefixed(prefix),
      trailingTrivia: trailingTrivia
    )
  }

func updateShapeLayer(layer: CAShapeLayer) {
  hasUpdate = false

  guard let path = layer.path else {
    return
  }

  let frame = path.boundingBox
  let anchor = CGPoint(
    x: -frame.origin.x / frame.size.width,
    y: -frame.origin.y / frame.size.height
  )
  maskLayer.path = path
  maskLayer.bounds = path.boundingBox
  maskLayer.anchorPoint = anchor

  gradientLayer.bounds = maskLayer.bounds
  gradientLayer.anchorPoint = anchor

  // setup gradient properties
  gradientLayer.start = start
  gradientLayer.end = end
  gradientLayer.numberOfColors = numberOfColors
  gradientLayer.colors = colors
  gradientLayer.opacity = Float(opacity)
  gradientLayer.type = type
}

static func swiftUIView(
  content: Content,
  behaviors: Behaviors? = nil
) -> SwiftUIView<Self, Content> {
  SwiftUIView(storage: content) {
    let view = Self()
    view.setContent(content, animated: false)
    return view
  }
  .configure { context in
    // We need to update the content of the existing view when the content is updated.
    if context.oldStorage != content {
      context.view.setContent(content, animated: context.animated)
      context.container.invalidateIntrinsicContentSize()
    }

    context.view.setBehaviors(behaviors)
  }
}

init(shapeLayer: ShapeLayerModel) {
  let results = shapeLayer.items.initializeNodeTree()
  let renderContainer = ShapeContainerLayer()
  self.renderContainer = renderContainer
  rootNode = results.rootNode
  super.init(layer: shapeLayer, size: .zero)
  contentsLayer.addSublayer(renderContainer)
  for container in results.renderContainers {
    renderContainer.insertRenderLayer(container)
  }
  rootNode?.updateTree(0, forceUpdates: true)
  // Use direct downcasting from `AnimatorNode` to `KeypathSearchable`
  // to avoid calling `_arrayForceCast` for performance reasons
  childKeypaths.append(contentsOf: results.childrenNodes.map { $0 as KeypathSearchable })
}

func rebuildOutputs(frame: CGFloat) {
  let path = BezierPath.star(
    position: properties.position.value.pointValue,
    outerRadius: properties.outerRadius.value.cgFloatValue,
    innerRadius: properties.innerRadius.value.cgFloatValue,
    outerRoundedness: properties.outerRoundedness.value.cgFloatValue,
    innerRoundedness: properties.innerRoundedness.value.cgFloatValue,
    numberOfPoints: properties.points.value.cgFloatValue,
    rotation: properties.rotation.value.cgFloatValue,
    direction: properties.direction
  )

  pathOutput.setPath(path, updateFrame: frame)
}

public mutating func next() -> [Base.Element]? {
  // In the end case, `lengths` is an empty range.
  if lengths.isEmpty {
    return nil
  }

  // The first iteration must produce the original sorted array, before any
  // permutations. We skip the permutation the first time so that we can
  // always mutate the array _before_ returning a slice, which avoids
  // copying when possible.
  if initial {
    initial = false
    return indexes[..<lengths.lowerBound].map { base[$0] }
  }

  if !indexes.nextPermutation(upperBound: lengths.lowerBound) {
    lengths.removeFirst()

    if lengths.isEmpty {
      return nil
    }
  }

  return indexes[..<lengths.lowerBound].map { base[$0] }
}

@inlinable
    public func distance(from start: CircularBuffer<Element>.Index, to end: CircularBuffer<Element>.Index) -> Int {
        let backingCount = self._buffer.count

        switch (start.isIndexGEQHeadIndex, end.isIndexGEQHeadIndex) {
        case (true, true):
            return end.backingIndex &- start.backingIndex
        case (true, false):
            return backingCount &- (start.backingIndex &- end.backingIndex)
        case (false, true):
            return -(backingCount &- (end.backingIndex &- start.backingIndex))
        case (false, false):
            return end.backingIndex &- start.backingIndex
        }
    }

var currentBestWriteMechanism: WriteMechanism {
    switch self.flushedChunks {
    case 0:
        return .nothingToBeWritten
    case 1:
        switch self.pendingWrites.first!.data {
        case .byteBuffer:
            return .scalarBufferWrite
        case .fileRegion:
            return .scalarFileWrite
        }
    default:
        let startIndex = self.pendingWrites.startIndex
        switch (
            self.pendingWrites[startIndex].data,
            self.pendingWrites[self.pendingWrites.index(after: startIndex)].data
        ) {
        case (.byteBuffer, .byteBuffer):
            return .vectorBufferWrite
        case (.byteBuffer, .fileRegion):
            return .scalarBufferWrite
        case (.fileRegion, _):
            return .scalarFileWrite
        }
    }
}

@nonobjc
  func addAnimation<KeyframeValue: AnyInterpolatable, ValueRepresentation>(
    for property: LayerProperty<ValueRepresentation>,
    keyframes: KeyframeGroup<KeyframeValue>,
    value keyframeValueMapping: (KeyframeValue) throws -> ValueRepresentation,
    context: LayerAnimationContext
  ) throws {
    if let customAnimation = try customizedAnimation(for: property, context: context) {
      add(customAnimation, timedWith: context)
    }

    else if
      let defaultAnimation = try defaultAnimation(
        for: property,
        keyframes: keyframes,
        value: keyframeValueMapping,
        context: context
      )
    {
      let timedAnimation = defaultAnimation.timed(with: context, for: self)
      add(timedAnimation, forKey: property.caLayerKeypath)
    }
  }

@nonobjc
  func addAnimations(
    for customPath: KeyframeGroup<BezierPath>,
    context: LayerAnimationContext,
    pathMultiplier: PathMultiplier = 1,
    transformPath: (CGPath) -> CGPath = { $0 },
    roundedCorners: RoundedCorners? = nil
  ) throws {
    let combinedKeyframes = try BezierPathKeyframe.combining(
      path: customPath,
      cornerRadius: roundedCorners?.radius
    )

    try addAnimation(
      for: .path,
      keyframes: combinedKeyframes,
      value: { pathKeyframe in
        var path = pathKeyframe.path
        if let cornerRadius = pathKeyframe.cornerRadius {
          path = path.roundCorners(radius: cornerRadius.cgFloatValue)
        }

        return transformPath(path.cgPath().duplicated(times: pathMultiplier))
      },
      context: context
    )
  }

private func addLinearGradientAnimations(
  for gradient: GradientShapeItem,
  context: LayerAnimationContext
) throws {
  type = .axial

  try addAnimation(
    for: .startPoint,
    keyframes: gradient.startPoint,
    value: { absoluteStartPoint in
      percentBasedPointInBounds(from: absoluteStartPoint.pointValue)
    },
    context: context
  )

  try addAnimation(
    for: .endPoint,
    keyframes: gradient.endPoint,
    value: { absoluteEndPoint in
      percentBasedPointInBounds(from: absoluteEndPoint.pointValue)
    },
    context: context
  )
}

private func gradientColorsCount(
  in context: LayerAnimationContext,
  gradient: GradientShapeItem
) throws -> Int {
  let colorsProperty = LayerProperty<[CGColor]>.colors.customizableProperty

  guard
    let colorsProperty,
    let customKeyframes = try context.valueProviderStore.customKeyframes(
      of: colorsProperty,
      for: AnimationKeypath(
        keys: context.currentKeypath.keys + colorsProperty.name.map { $0.rawValue }
      ),
      context: context
    )
  else {
    return gradient.numberOfColors
  }

  return customKeyframes.keyframes[0].value.count
}

@nonobjc
  func addAnimations(
    for rectangle: Rectangle,
    context: LayerAnimationContext,
    pathMultiplier: PathMultiplier,
    roundedCorners: RoundedCorners?
  ) throws {
    try addAnimation(
      for: .path,
      keyframes: try rectangle.combinedKeyframes(roundedCorners: roundedCorners),
      value: { keyframe in
        BezierPath.rectangle(
          position: keyframe.position.pointValue,
          size: keyframe.size.sizeValue,
          cornerRadius: keyframe.cornerRadius.cgFloatValue,
          direction: rectangle.direction
        )
        .cgPath()
        .duplicated(times: pathMultiplier)
      },
      context: context
    )
  }

@nonobjc
  private func addStarAnimation(
    for star: Star,
    context: LayerAnimationContext,
    pathMultiplier: PathMultiplier
  ) throws {
    try addAnimation(
      for: .path,
      keyframes: try star.combinedKeyframes(),
      value: { keyframe in
        BezierPath.star(
          position: keyframe.position.pointValue,
          outerRadius: keyframe.outerRadius.cgFloatValue,
          innerRadius: keyframe.innerRadius.cgFloatValue,
          outerRoundedness: keyframe.outerRoundness.cgFloatValue,
          innerRoundedness: keyframe.innerRoundness.cgFloatValue,
          numberOfPoints: keyframe.points.cgFloatValue,
          rotation: keyframe.rotation.cgFloatValue,
          direction: star.direction
        )
        .cgPath()
        .duplicated(times: pathMultiplier)
      },
      context: context
    )
  }
